import { useState, useEffect } from 'react';
import api from '../../services/api';
import toast from 'react-hot-toast';
import { FiPlus, FiTrash2, FiShoppingCart } from 'react-icons/fi';

export default function VentaForm() {
  const [productos, setProductos] = useState([]);
  const [clienteNombre, setClienteNombre] = useState('');
  const [clienteDocumento, setClienteDocumento] = useState('');
  const [items, setItems] = useState([]);
  const [currentProducto, setCurrentProducto] = useState('');
  const [cantidad, setCantidad] = useState(1);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const fetchProductos = async () => {
      try {
        const res = await api.get('/productos');
        setProductos(res.data.filter(p => p.activo && p.stock_actual > 0));
      } catch (error) {
        toast.error('Error al cargar productos');
      }
    };
    fetchProductos();
  }, []);

  const addItem = () => {
    if (!currentProducto || cantidad <= 0) return;
    const producto = productos.find(p => p.id === parseInt(currentProducto));
    if (!producto) return;
    if (producto.stock_actual < cantidad) {
      toast.error(`Stock insuficiente de ${producto.nombre}. Disponible: ${producto.stock_actual}`);
      return;
    }
    setItems([...items, {
      producto_id: producto.id,
      producto_nombre: producto.nombre,
      cantidad: parseInt(cantidad),
      precio_unitario: parseFloat(producto.precio_venta)
    }]);
    setCurrentProducto('');
    setCantidad(1);
  };

  const removeItem = (index) => {
    setItems(items.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!clienteNombre.trim()) {
      toast.error('Ingrese el nombre del cliente');
      return;
    }
    if (items.length === 0) {
      toast.error('Agregue al menos un producto');
      return;
    }
    setLoading(true);
    try {
      await api.post('/ventas', {
        cliente_nombre: clienteNombre,
        cliente_documento: clienteDocumento,
        items: items.map(i => ({
          producto_id: i.producto_id,
          cantidad: i.cantidad
        }))
      });
      toast.success('✅ Venta registrada exitosamente');
      setClienteNombre('');
      setClienteDocumento('');
      setItems([]);
    } catch (error) {
      toast.error(error.response?.data?.error || 'Error al registrar venta');
    } finally {
      setLoading(false);
    }
  };

  const total = items.reduce((sum, i) => sum + (i.cantidad * i.precio_unitario), 0);

  return (
    <div className="space-y-6">
      <div className="flex items-center space-x-3">
        <FiShoppingCart className="text-3xl text-primary-600" />
        <h1 className="text-3xl font-bold text-gray-800">Registrar Venta</h1>
      </div>
      
      <form onSubmit={handleSubmit} className="card p-6 space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Nombre del cliente *</label>
            <input
              type="text"
              value={clienteNombre}
              onChange={e => setClienteNombre(e.target.value)}
              required
              className="input-field"
              placeholder="Ej: Juan Pérez"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Documento (opcional)</label>
            <input
              type="text"
              value={clienteDocumento}
              onChange={e => setClienteDocumento(e.target.value)}
              className="input-field"
              placeholder="DNI, RUC, etc."
            />
          </div>
        </div>
        
        <div className="border-t pt-6">
          <h3 className="text-lg font-semibold text-gray-800 mb-4">Agregar Productos</h3>
          <div className="flex flex-col sm:flex-row gap-3">
            <select
              value={currentProducto}
              onChange={e => setCurrentProducto(e.target.value)}
              className="input-field flex-1"
            >
              <option value="">Seleccione un producto</option>
              {productos.map(p => (
                <option key={p.id} value={p.id}>
                  {p.nombre} - Stock: {p.stock_actual} - ${parseFloat(p.precio_venta).toFixed(2)}
                </option>
              ))}
            </select>
            <input
              type="number"
              placeholder="Cantidad"
              value={cantidad}
              onChange={e => setCantidad(e.target.value)}
              min="1"
              className="input-field w-32"
            />
            <button type="button" onClick={addItem} className="btn-primary flex items-center space-x-2">
              <FiPlus /> <span>Agregar</span>
            </button>
          </div>
        </div>
        
        {items.length > 0 && (
          <div className="border rounded-lg overflow-hidden">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Producto</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Cantidad</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Precio</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Subtotal</th>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200">
                {items.map((item, idx) => (
                  <tr key={idx}>
                    <td className="px-4 py-3 text-sm">{item.producto_nombre}</td>
                    <td className="px-4 py-3 text-sm">{item.cantidad}</td>
                    <td className="px-4 py-3 text-sm">${item.precio_unitario.toFixed(2)}</td>
                    <td className="px-4 py-3 text-sm font-semibold">${(item.cantidad * item.precio_unitario).toFixed(2)}</td>
                    <td className="px-4 py-3">
                      <button type="button" onClick={() => removeItem(idx)} className="text-red-600 hover:text-red-800">
                        <FiTrash2 />
                      </button>
                    </td>
                  </tr>
                ))}
                <tr className="bg-gray-50 font-bold">
                  <td colSpan="3" className="px-4 py-3 text-right">Total:</td>
                  <td className="px-4 py-3 text-primary-600 text-lg">${total.toFixed(2)}</td>
                  <td></td>
                </tr>
              </tbody>
            </table>
          </div>
        )}
        
        <div className="flex justify-end">
          <button type="submit" disabled={loading} className="btn-success flex items-center space-x-2 px-6 py-3 text-lg">
            {loading ? (
              <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
            ) : (
              <>
                <FiShoppingCart />
                <span>Registrar Venta</span>
              </>
            )}
          </button>
        </div>
      </form>
    </div>
  );
}
